// =====================
// Thresholds
// =====================
const EDGE_THRESHOLD      = 0.04;
const MOMENTUM_WEIGHT     = 0.25;  // log-odds shift scale
const RSI_NEUTRAL         = 50;
const RSI_NORM_RANGE      = 20;
const ATR_FALLBACK        = 0.02;

const logit   = (p) => Math.log(p / (1 - p));
const sigmoid = (x) => 1 / (1 + Math.exp(-x));
const clamp   = (v, lo, hi) => Math.max(lo, Math.min(hi, v));

// =====================
// Event-scope features
// =====================
const klines  = ctx.underlying.klines;
const closes  = klines.map(k => k.close);
const highs   = klines.map(k => k.high);
const lows    = klines.map(k => k.low);
const n       = closes.length;

// ATR(14) Wilder
let atr = 0;
if (n >= 15) {
  const trs = [];
  for (let i = 1; i < n; i++) {
    const tr = Math.max(highs[i]-lows[i], Math.abs(highs[i]-closes[i-1]), Math.abs(lows[i]-closes[i-1]));
    trs.push(tr);
  }
  let atrVal = trs.slice(0, 14).reduce((a, b) => a + b, 0) / 14;
  for (let i = 14; i < trs.length; i++) atrVal = (atrVal * 13 + trs[i]) / 14;
  atr = atrVal;
}
const spot     = closes[n - 1];
const atrRatio = spot > 0 ? atr / spot : ATR_FALLBACK;
const atrScale = atrRatio > 0 ? atrRatio : ATR_FALLBACK;

// Returns
const lastBar = klines[n - 1];
const ret15m  = (lastBar.close - lastBar.open) / lastBar.open;
const ret1h   = n >= 2  ? (closes[n-1] - closes[n-2])  / closes[n-2]  : 0;
const ret4h   = n >= 5  ? (closes[n-1] - closes[n-5])  / closes[n-5]  : 0;
const ret24h  = n >= 25 ? (closes[n-1] - closes[n-25]) / closes[n-25] : 0;

// RSI(14)
const rsiVal    = ctx.helpers.rsi(closes, 14);
const rsiSignal = clamp((rsiVal - RSI_NEUTRAL) / RSI_NORM_RANGE, -1, 1);

// EMA(12) / EMA(26)
const ema12Arr  = ctx.helpers.emaArray(closes, 12);
const ema26Arr  = ctx.helpers.emaArray(closes, 26);
const ema12     = ema12Arr.at(-1);
const ema26     = ema26Arr.at(-1);
const emaCross  = ema12 - ema26;
const emaSignal = clamp(emaCross / spot / atrScale, -1, 1);

// MACD histogram
const macdLine   = ema12Arr.map((v, i) => v - ema26Arr[i]);
const signalLine = ctx.helpers.emaArray(macdLine, 9);
const macdHist   = macdLine.at(-1) - signalLine.at(-1);
const macdSignal = clamp(macdHist / spot / (atrScale * 0.5), -1, 1);

// Short momentum (normalized returns)
const sig15m = clamp(ret15m / atrScale, -1, 1);
const sig1h  = clamp(ret1h  / atrScale, -1, 1);
const sig4h  = clamp(ret4h  / (atrScale * 2), -1, 1);

// Composite signal → log-odds shift
const compositeSignal = (
  sig15m    * 0.10 +
  sig1h     * 0.20 +
  sig4h     * 0.20 +
  rsiSignal * 0.20 +
  emaSignal * 0.15 +
  macdSignal* 0.15
);
const logOddsShift = compositeSignal * MOMENTUM_WEIGHT;

// =====================
// Per-market
// =====================
const et = ctx.helpers.eventPrimaryQuestionType(ctx);

return ctx.markets.map(market => {
  try {
    if (market.closed || market.hoursToExpiry < 0) {
      return { question: market.question, decision: "hold", reason: "closed or expired" };
    }

    const mCtx = { market, underlying: ctx.underlying, timing: ctx.timing };

    // Single-type dispatch (above/below only for this event)
    let pYesBase;
    if (market.questionType === "above") {
      pYesBase = ctx.helpers.bsAbove(mCtx);
    } else if (market.questionType === "below") {
      pYesBase = 1 - ctx.helpers.bsAbove(mCtx);
    } else {
      return { question: market.question, decision: "hold", reason: `unsupported type: ${market.questionType}` };
    }

    const pYes  = sigmoid(logit(clamp(pYesBase, 1e-6, 1 - 1e-6)) + logOddsShift);
    const probs = ctx.helpers.binaryProbsFromYesProb(mCtx, pYes);
    const edges = ctx.helpers.edgeFromProbs(probs, mCtx);
    const best  = edges[0].edge >= edges[1].edge ? edges[0] : edges[1];

    const base = {
      question:      market.question,
      questionType:  market.questionType,
      strike:        market.strike,
      distancePct:   market.strike ? ((market.strike - spot) / spot * 100).toFixed(2) + "%" : null,
      hoursToExpiry: market.hoursToExpiry,
      pYesBase:      +pYesBase.toFixed(4),
      pYesAdj:       +pYes.toFixed(4),
      probs:         probs.map(p => +p.toFixed(4)),
    };

    if (best.edge < EDGE_THRESHOLD) {
      return { ...base, decision: "hold", bestEdge: +best.edge.toFixed(4), edges };
    }
    return {
      ...base,
      decision:    "buy",
      side:        best.label,
      fairPrice:   +best.fairPrice.toFixed(4),
      marketPrice: +best.marketPrice.toFixed(4),
      edge:        +best.edge.toFixed(4),
      edges,
    };
  } catch (err) {
    return { question: market.question, decision: "hold", reason: String(err) };
  }
});
